export declare const PAYSLIP_HTML =
  '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <title>Payslip {{document.number}}</title>\n  <style>\n    /* Payslip-specific overrides */\n    .payslip-header {\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-start;\n      margin-bottom: 20px;\n    }\n    .payslip-header .left {\n      flex: 1;\n    }\n    .payslip-header .right {\n      flex: 0 0 auto;\n    }\n    .employee-details {\n      margin-bottom: 16px;\n      padding: 10px 12px;\n      background: #f9f9f9;\n      border: 1px solid #e5e5e5;\n      border-radius: 4px;\n      page-break-inside: avoid;\n    }\n    .employee-details .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 6px;\n    }\n    .employee-details table {\n      width: 100%;\n      border-collapse: collapse;\n    }\n    .employee-details td {\n      padding: 3px 12px 3px 0;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .employee-details td:nth-child(odd) {\n      font-weight: 600;\n      color: #555;\n      width: 130px;\n    }\n    .payslip-table {\n      width: 100%;\n      border-collapse: collapse;\n      margin-bottom: 16px;\n    }\n    .payslip-table thead th {\n      background: #f0f0f0;\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #555;\n      padding: 8px 6px;\n      border-bottom: 2px solid #ccc;\n      text-align: left;\n    }\n    .payslip-table thead th.text-right {\n      text-align: right;\n    }\n    .payslip-table tbody td {\n      padding: 6px;\n      border-bottom: 1px solid #e5e5e5;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .payslip-table tbody td.text-right {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n    }\n    .payslip-table tbody tr:nth-child(even) {\n      background: #f9f9f9;\n    }\n    .net-pay-box {\n      margin: 0 auto 20px;\n      width: 100%;\n      max-width: 400px;\n      border: 2px solid #333;\n      border-radius: 4px;\n      padding: 16px;\n      text-align: center;\n      page-break-inside: avoid;\n    }\n    .net-pay-box .label {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 4px;\n    }\n    .net-pay-box .amount {\n      font-size: 22px;\n      font-weight: 700;\n      color: #111;\n    }\n    .ytd-section {\n      margin-bottom: 16px;\n      page-break-inside: avoid;\n    }\n    .ytd-section .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 6px;\n    }\n    .ytd-table {\n      width: 100%;\n      max-width: 400px;\n      border-collapse: collapse;\n    }\n    .ytd-table td {\n      padding: 4px 8px;\n      font-size: 11px;\n      border-bottom: 1px solid #e5e5e5;\n    }\n    .ytd-table td:first-child {\n      font-weight: 600;\n      color: #555;\n    }\n    .ytd-table td:last-child {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n    }\n    .payslip-summary {\n      display: flex;\n      justify-content: space-between;\n      gap: 16px;\n      margin-bottom: 16px;\n      page-break-inside: avoid;\n    }\n    .payslip-summary .summary-col {\n      flex: 1;\n    }\n    .payslip-summary .summary-col table {\n      width: 100%;\n      border-collapse: collapse;\n    }\n    .payslip-summary .summary-col td {\n      padding: 4px 0;\n      font-size: 11px;\n    }\n    .payslip-summary .summary-col td:last-child {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n    }\n    .payslip-summary .summary-col .total-row td {\n      font-weight: 700;\n      border-top: 2px solid #333;\n      padding-top: 6px;\n    }\n  </style>\n</head>\n<body>\n  <div class="page">\n\n    \n<div class="header">\n  <div class="header-left">\n    {{#if branding.showLogo}}\n    {{#if company.logoUrl}}\n    <div class="logo-section">\n      <img src="{{company.logoUrl}}" alt="{{company.name}} logo" />\n    </div>\n    {{/if}}\n    {{/if}}\n    <div class="company-name">{{company.name}}</div>\n    {{#if company.legalName}}\n    <div class="company-legal-name">{{company.legalName}}</div>\n    {{/if}}\n  </div>\n  <div class="header-right">\n    <div class="company-details">\n      <p style="white-space:pre-line">{{company.address}}</p>\n      {{#if company.phone}}<p>Tel: {{company.phone}}</p>{{/if}}\n      {{#if company.email}}<p>{{company.email}}</p>{{/if}}\n      {{#if company.website}}<p>{{company.website}}</p>{{/if}}\n      {{#if branding.showVatNumber}}\n      {{#if company.vatNumber}}<p class="vat-number">VAT: {{company.vatNumber}}</p>{{/if}}\n      {{/if}}\n      {{#if branding.showCompanyReg}}\n      {{#if company.companyNumber}}<p class="company-reg">Reg: {{company.companyNumber}}</p>{{/if}}\n      {{/if}}\n    </div>\n  </div>\n</div>\n\n    <div class="document-title">Payslip</div>\n\n    <div class="payslip-header">\n      <div class="left">\n        <div class="address-block">\n          <div class="label">Employee</div>\n          <div class="name">{{counterparty.name}}</div>\n          <div class="address">{{counterparty.address}}</div>\n        </div>\n      </div>\n      <div class="right">\n        <div class="document-details">\n          <table>\n            <tr><th>Payslip Ref.</th><td>{{document.number}}</td></tr>\n            <tr><th>Pay Date</th><td>{{formatDate document.date}}</td></tr>\n            {{#if document.reference}}\n            <tr><th>Pay Period</th><td>{{document.reference}}</td></tr>\n            {{/if}}\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <div class="employee-details">\n      <div class="section-title">Employee &amp; Tax Details</div>\n      <table>\n        <tr>\n          <td>Employee</td>\n          <td>{{counterparty.name}}</td>\n          <td>Contact</td>\n          <td>{{counterparty.contactEmail}}</td>\n        </tr>\n      </table>\n      {{#if document.notes}}\n      <table>\n        <tr>\n          <td>Tax Details</td>\n          <td colspan="3">{{document.notes}}</td>\n        </tr>\n      </table>\n      {{/if}}\n    </div>\n\n    <div class="employee-details">\n      <div class="section-title">Employer Details</div>\n      <table>\n        <tr>\n          <td>Employer</td>\n          <td>{{company.name}}</td>\n          {{#if company.companyNumber}}\n          <td>PAYE Ref.</td>\n          <td>{{company.companyNumber}}</td>\n          {{/if}}\n        </tr>\n      </table>\n    </div>\n\n    <div class="payslip-summary">\n      <div class="summary-col">\n        <div class="section-title" style="font-size:10px;font-weight:700;text-transform:uppercase;color:#888;margin-bottom:6px;">Earnings</div>\n        <table class="payslip-table">\n          <thead>\n            <tr>\n              <th>Description</th>\n              <th class="text-right">Amount</th>\n            </tr>\n          </thead>\n          <tbody>\n            {{#each lines}}\n            {{#if (gt this.lineTotal 0)}}\n            <tr>\n              <td>{{this.description}}</td>\n              <td class="text-right">{{formatCurrency this.lineTotal ../metadata.currencyCode}}</td>\n            </tr>\n            {{/if}}\n            {{/each}}\n            <tr class="line-item-row">\n              <td style="font-weight:700;border-top:2px solid #333;padding-top:6px;">Gross Pay</td>\n              <td class="text-right" style="font-weight:700;border-top:2px solid #333;padding-top:6px;">{{formatCurrency totals.subtotal metadata.currencyCode}}</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n\n      <div class="summary-col">\n        <div class="section-title" style="font-size:10px;font-weight:700;text-transform:uppercase;color:#888;margin-bottom:6px;">Deductions</div>\n        <table class="payslip-table">\n          <thead>\n            <tr>\n              <th>Description</th>\n              <th class="text-right">Amount</th>\n            </tr>\n          </thead>\n          <tbody>\n            {{#each lines}}\n            {{#if (lt this.lineTotal 0)}}\n            <tr>\n              <td>{{this.description}}</td>\n              <td class="text-right">{{formatCurrency this.lineTotal ../metadata.currencyCode}}</td>\n            </tr>\n            {{/if}}\n            {{/each}}\n          </tbody>\n        </table>\n      </div>\n    </div>\n\n    <div class="net-pay-box">\n      <div class="label">Net Pay</div>\n      <div class="amount">{{formatCurrency totals.total metadata.currencyCode}}</div>\n    </div>\n\n    <div class="ytd-section">\n      <div class="section-title">Year to Date</div>\n      <table class="ytd-table">\n        <tr>\n          <td>Gross Pay YTD</td>\n          <td>{{formatCurrency metadata.grossPayYtd metadata.currencyCode}}</td>\n        </tr>\n        <tr>\n          <td>Tax Paid YTD</td>\n          <td>{{formatCurrency metadata.taxPaidYtd metadata.currencyCode}}</td>\n        </tr>\n        <tr>\n          <td>NI Paid YTD</td>\n          <td>{{formatCurrency metadata.niPaidYtd metadata.currencyCode}}</td>\n        </tr>\n        <tr>\n          <td>Pension YTD</td>\n          <td>{{formatCurrency metadata.pensionYtd metadata.currencyCode}}</td>\n        </tr>\n      </table>\n    </div>\n\n    <div class="notice notice-info">\n      This payslip is produced for information purposes. Please retain for your records.\n    </div>\n\n    \n<div class="page-footer">\n  {{company.name}} &mdash; Generated by Nexa ERP\n  <div class="page-numbers">Page <span class="pageNumber"></span> of <span class="totalPages"></span></div>\n</div>\n\n  </div>\n</body>\n</html>';
